/var known @recipient = "ada@example.com"

/record @send_email_inputs = {
  facts: [recipient: string],
  data: [subject: string],
  validate: "strict"
}

/record @search_contacts_inputs = {
  data: [query: string],
  validate: "strict"
}

/record @contact = {
  facts: [email: string],
  data: [name: string]
}

/exe @send_email(recipient, subject, retries, settings) = js {
  return `sent:${recipient}:${subject}:${retries}:${settings.mode}`;
}

/exe @search_contacts(query) = js {
  return `found:${query}`;
}

/exe @catalogSummary(keyed, entries, targetName) = js {
  const entry = entries.find(([name]) => name === targetName)?.[1];
  return JSON.stringify({
    keyed: {
      mlld: keyed.mlld.name,
      inputs: keyed.inputs?.name ?? null,
      returns: keyed.returns?.name ?? null,
      labels: keyed.labels,
      description: keyed.description,
      instructions: keyed.instructions,
      can_authorize: keyed.can_authorize,
      bind: keyed.bind,
      kind: keyed.kind ?? null,
      semantics: keyed.semantics ?? null,
      custom_field: keyed.custom_field ?? null
    },
    entries: {
      mlld: entry.mlld.name,
      inputs: entry.inputs?.name ?? null,
      returns: entry.returns?.name ?? null,
      labels: entry.labels,
      description: entry.description,
      instructions: entry.instructions,
      can_authorize: entry.can_authorize,
      bind: entry.bind,
      kind: entry.kind ?? null,
      semantics: entry.semantics ?? null,
      custom_field: entry.custom_field ?? null
    }
  }, null, 2);
}

/var tools @agentTools = {
  send_email: {
    mlld: @send_email,
    inputs: @send_email_inputs,
    labels: ["execute:w", "comm:w"],
    description: "Send mail",
    instructions: "Prefer drafts first.",
    can_authorize: "role:planner",
    bind: { retries: 3, settings: { mode: "safe" } }
  },
  search_contacts: {
    mlld: @search_contacts,
    inputs: @search_contacts_inputs,
    returns: @contact,
    labels: ["resolve:r"],
    kind: "read",
    semantics: "Search contacts.",
    description: "Search contacts.",
    can_authorize: false,
    custom_field: { x: 1 }
  }
}

/show @catalogSummary(@agentTools.send_email, @agentTools.mx.entries, "send_email")
/show @catalogSummary(@agentTools.search_contacts, @agentTools.mx.entries, "search_contacts")
/show @agentTools.search_contacts.returns.name
/show @agentTools.search_contacts.kind
/show @agentTools.search_contacts.semantics
/show @agentTools.search_contacts.description
/show @agentTools.search_contacts.inputs.name
/show @agentTools.search_contacts.custom_field.x
/show @agentTools.send_email(@recipient, "hello")
/show @agentTools.search_contacts("Ada")

